var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"와아, 사람 정말 많다!","JPN":"わあ、人がいっぱい！","ENG":"Wow! Look at all these people!","TWN":"哇，好多人喔！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠, 저 사람들 모두 아빠 직원이 되는 거야?","JPN":"パパ、あの人たちがみんなパパの会社の社員になるの？","ENG":"Daddy, are all these people gonna work for you?","TWN":"爸爸，他們都會成為爸爸的員工嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 그러면 좋겠구나.","JPN":"ハハ、そうだったらいいね。","ENG":"Haha, I wish that was the case.","TWN":"哈哈，那樣當然是最好的。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지금 있는 언니 오빠들을 도와 주려면 아주 훌륭한 사람들이 필요해.","JPN":"今いるお姉さんとお兄さんたちを助けてあげるためには、とても立派な人たちが必要なんだ。","ENG":"But we can only afford to have the best to help our company.","TWN":"必須是很厲害的人，才能幫得上哥哥姊姊們。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저 중에서 그런 사람들을 찾을 수 있게 시그마도 도와 주겠니?","JPN":"あの中からそんな人を探せるように、シグマも手伝ってくれるかい？","ENG":"So, will you help me find those kinds of people, Sigma?","TWN":"西格瑪可以一起幫忙從那些人當中找到合適的人嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응! 걱정 마, 아빠! 나한테 맡겨!","JPN":"うん！　心配しないで、パパ！　私に任せて！","ENG":"Okay! Leave it to me, Daddy!","TWN":"可以！爸爸放心！交給我！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님, 곧 예정된 면접 시간입니다.","JPN":"社長、もうすぐ予定していた面接のお時間です。","ENG":"Boss, it's almost time for the interviews.","TWN":"老闆，快到面試時間了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그런데……. 문제가 한 가지 생겼어요.","JPN":"でも……一つ問題があります。","ENG":"But... there has been a slight issue.","TWN":"不過……現在有點問題。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"미나 양 때문인가?","JPN":"ミナ君のことか？","ENG":"Is it because of Mina?","TWN":"是因為米娜的關係嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"문제라니?","JPN":"問題？","ENG":"An issue?","TWN":"什麼問題？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"네. 역시 짐작하고 계셨군요.","JPN":"はい。やっぱりご存じでしたか。","ENG":"Yes. So you are already aware.","TWN":"對，老闆也有發現到嗎？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"미나 씨가 충원을 원하지 않는다고 해서요.","JPN":"ヒルデ小隊長が<color=#ffd34c>指示に従える奴がいれば構わん</color>とおっしゃられたので募集を出したのですが、","ENG":"Commander Hilde said she <color=#ffd34c>\\"doesn't care as long as that person can follow orders,\\"</color> so I posted the recruitment notice,","TWN":"希爾德小隊長說<color=#ffd34c>只要能聽從指令就好，其他無所謂</color>。所以我還特地寫在徵才內容上呢。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"힐데 소대장님께서 <color=#ffd34c>지시에 따를 수 있는 녀석이 있으면 상관없다</color>고 하시길래 공고를 올렸는데, 어떡할까요?","JPN":"ミナさんが新しい人を迎えたくないと言うんです。どうしましょうか？","ENG":"but Mina doesn't seem to want a new member. What should we do?","TWN":"但米娜說她不希望徵人進來，怎麼辦才好？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음. 힐데 소대장의 조건도 난제이긴 하지만….","JPN":"ふむ。ヒルデ小隊長の条件も難題だが……","ENG":"Hmm. Commander Hilde’s condition is also a conundrum...","TWN":"嗯嗯，希爾德小隊長的條件是有點難度，不過…"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양도 정신적으로 많이 지쳐 있는 모양이군.","JPN":"ミナ君も精神的にだいぶ疲れているようだな。","ENG":"And Mina also seems to be mentally exhausted.","TWN":"米娜的精神狀況似乎不太好。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"음? 바깥이 소란스러운 것 같은데?","JPN":"うん？　外が騒がしいが。","ENG":"Hmm? Why is it so loud out there?","TWN":"嗯？外面在吵什麼？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"앗, 설마 지원자들 중에 누가 난동이라도……","JPN":"あっ、まさか志願者の誰かが暴れて……？","ENG":"Oh, I will go see if one of the applicants is stirring up a fight...","TWN":"該不會是應徵者中有人在鬧事吧……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"금방 알아보고 오겠습니다. 잠시만 기다려 주세요.","JPN":"すぐ調べてきます。少々お待ちください。","ENG":"It will only take a minute, so please wait.","TWN":"老闆等我一下，我去看看怎麼回事。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아닐세. 나도 같이 가지.","JPN":"いや。私も一緒に行こう。","ENG":"No, I will go with.","TWN":"不，我也一起去。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"당신들 지금 뭐 하자는 거야? 면접 준비 중인 거 안 보여?","JPN":"あんたたち、何しに来たのよ？　今、面接の準備してるのわからない？","ENG":"Who the heck are you guys? Can't you see we're trying to conduct some interviews?","TWN":"你們這是在做什麼？沒看到我們正在準備面試嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L36_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"말하지 않았나? 관리국이 보내서 왔다고.","JPN":"言ったはずだが。管理局から来たと。","ENG":"Didn't I already say? We were sent here by the Administration.","TWN":"我剛才不是說了？是管理局派我們來的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"코핀 컴퍼니를 압수 수색하라더군. 서류부터 장비까지 전부.","JPN":"コフィンカンパニーを家宅捜索しろってな。書類から装備まで、全部。","ENG":"We have an order to conduct a search and seizure on Coffin Company. Including all documents and equipment.","TWN":"現在要對科芬公司進行搜索扣押，從資料到裝備全都要帶走！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"과, 관리국에서?","JPN":"か、管理局から？","ENG":"F-from the Administration?","TWN":"管，管理局派來的？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이해가 안 되네. 관리국이 왜 당신들에게 그런 일을 맡긴다는 거야?","JPN":"わかるように説明してほしいわね。どうして管理局があなたたちにそんな仕事を任せたの？","ENG":"I don't understand. Why would the Administration entrust such a task to you, of all people?","TWN":"我不太明白，管理局為什麼會把這件事交給你們？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"글쎄. 너무 고상한 분들이라 흙먼지 마시기 싫으신 거겠지.","JPN":"さあな。あまりにも上品な方々だから、土煙を浴びたくないのだろう。","ENG":"Who knows? Maybe they didn't want to get their hands dirty.","TWN":"我怎麼知道？可能因為他們比較嬌貴，不想做這些雜事吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"자. 이게 오늘 나온 따끈따끈한 허가서다.","JPN":"さあ。これが今日できてほやほやの許可書だ。","ENG":"Here's the warrant. The ink hasn't even fully dried yet.","TWN":"拿去，這是今天剛開的，還熱騰騰的搜索票。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L45_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"필요하다면 무력 시위도 승인한다더군. 직접 확인해 봐.","JPN":"必要なら武力行使も承認するってよ。自分の目で確認してみろ。","ENG":"We have been given permission to use force if necessary. See for yourself.","TWN":"上面說，必要時可進行武力鎮壓。你自己看清楚吧。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"어이, 제시카. 여기 찍힌 도장…. 가짜는 아닌 것 같은데.","JPN":"おい、ジェシカ。このハンコ……偽物じゃなさそうだぞ。","ENG":"Hey, Jessica. The stamp on that thing... I don't think it's fake.","TWN":"喂，潔西卡，你看這裡有蓋章…應該是真的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"자, 자. 돈 받고 일하는 신세끼리 피차 곤란할 일 없게 하자고.","JPN":"さあさあ。お互いに金もらって働いてる者同士、大人の対応をしようぜ。","ENG":"All right, then. As one mercenary to another, let's not make a mess out of this, okay?","TWN":"好了好了，大家都是拿錢辦事的，麻煩不要造成彼此的困擾。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"다들 움직여. 1순위는 그 머신 갑인가 하는 로봇이다.","JPN":"みんな動け。最優先はあのマシーン-甲-とかいうロボットだ。","ENG":"Move it, y'all! First thing on the list is a robot called Machine G.A.P.","TWN":"開始行動！最重要的就是那個機甲還機器人的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"우왓……?! 이런 미친!","JPN":"うわっ……！？　おい！","ENG":"Whoa...?! Watch it!","TWN":"欸欸……？！你在發什麼瘋！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그건 우리 사장 거야. 못 줘.","JPN":"それは社長のもの。あげられない。","ENG":"You can't have it. It's Boss's.","TWN":"那是我們老闆的，不能給你。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"제시카가 남의 물건 마음대로 가져가는 사람은 도둑놈이랬어.","JPN":"ジェシカが人のものを勝手に持っていく人は泥棒だって言ってた。","ENG":"Jessica said that people who take others' stuff are thieves.","TWN":"潔西卡說擅自拿別人的東西是小偷的行為。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카! 너 왜 이럴 때만 말 잘 듣고 그래?!","JPN":"オルカ！　こういう時だけいい子にならないでくれる！？","ENG":"Orca! Why do you only listen to me in times like this?!","TWN":"奧爾卡！你為什麼專挑這種時候聽話？！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"쳇. 일이 귀찮아졌군.","JPN":"チッ。めんどくさいことになったな。","ENG":"Tch! So this is how you're gonna play, eh?","TWN":"嘖，事情變得有點棘手呢。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"조용히 넘어가기 싫으면 어쩔 수 없지. 규정대로 하는 수밖에.","JPN":"大人しく渡す気がないなら、仕方ない。規定どおりにするしかないぞ。","ENG":"If you're not willing to cooperate, we have no choice but to do it by the book.","TWN":"要是不肯乖乖配合，那休怪我們照規定來！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"이 자식들이… 어디 한 번 해보자 이거야?","JPN":"この……やろうってのか？","ENG":"How dare you... So you wanna start this, huh?","TWN":"你們這些傢伙…是要打一架的意思嗎？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"사상자 나오면 골치 아파져. 적당히 힘 조절 해.","JPN":"死傷者が出たら面倒くさくなる。適当に手加減して。","ENG":"Go easy on them. It'll get messy if there are any causalities.","TWN":"萬一有人受傷就不好了，力道要拿捏一下。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"힘 조절? 델타 세븐 덕 좀 봤다고 아주 세상 잘나셨구만?","JPN":"手加減？　デルタセブンのおかげで得したくせに偉そうに。","ENG":"Go easy? You think you're some big shot because Delta Seven has your back?","TWN":"拿捏力道？沾了第七三角洲部隊的光就拿翹了是吧？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"뭐 해! 제압해!","JPN":"何してんだ！　制圧しろ！","ENG":"Boys! Get 'em!","TWN":"還不動手！制服他們！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};